/* ---------- Scroll progress "sulco" ---------- */
function GrooveProgress() {
  const [pct, setPct] = useState(0);
  useEffect(() => {
    const onScroll = () => {
      const h = document.documentElement;
      const scrolled = h.scrollTop;
      const max = h.scrollHeight - h.clientHeight;
      setPct(max > 0 ? (scrolled / max) * 100 : 0);
    };
    window.addEventListener("scroll", onScroll, { passive: true });
    return () => window.removeEventListener("scroll", onScroll);
  }, []);
  return (
    <div
      className="hidden lg:block fixed left-0 top-0 h-full z-40"
      style={{ width: 3, background: "rgba(var(--paper-rgb),0.08)" }}
      aria-hidden="true"
    >
      <div
        style={{
          width: "100%",
          height: `${pct}%`,
          background: `linear-gradient(180deg, ${COLORS.paper}, ${COLORS.paperDim})`,
          transition: "height 0.1s linear",
        }}
      />
    </div>
  );
}

