/* ============================================================
   SEO — cole isto no <head> do index.html do projeto
   (fora do componente React; não pode ser definido via JSX puro)
   ============================================================

<title>Hifive Discos e Bar — Música no lugar certo | Meireles, Fortaleza</title>
<meta name="description" content="Loja de discos de vinil e bar no Meireles, Fortaleza. Catálogo de rock, MPB, jazz, soul e mais. Sessões de discotecagem e shows ao vivo." />
<link rel="icon" href="/favicon.ico" />
<meta property="og:title" content="Hifive Discos e Bar — Música no lugar certo" />
<meta property="og:description" content="Loja de discos de vinil e bar no Meireles, Fortaleza." />
<meta property="og:image" content="https://SEU-DOMINIO/og-image.jpg" />
<meta property="og:url" content="https://SEU-DOMINIO" />
<meta property="og:type" content="website" />
<meta name="twitter:card" content="summary_large_image" />
============================================================ */
